const urlString = $.input.urls || '';
const urls = urlString.split(',').map(function(u) { return u.trim(); }).filter(function(u) { return u.length > 0 && (u.startsWith('http://') || u.startsWith('https://')); });
return { urls: urls, urlCount: urls.length };

const urls = $.steps.parseUrls.output.urls;
const iterations = $.steps.scrapePages.response?.iterations || [];
let allContent = '';
let successCount = 0;
let failCount = 0;
const pageResults = [];

urls.forEach(function(url, i) {
  const iter = iterations[i] || {};
  const resp = iter.scrapePage?.response?.data || iter.scrapePage?.response || {};
  const md = resp.markdown || resp.content || '';

  if (md) {
    successCount++;
    allContent += '=== PAGE ' + (i + 1) + ' ===\nURL: ' + url + '\nContent:\n' + md.slice(0, 3000) + '\n\n';
    pageResults.push([String(i + 1), url, 'success', String(md.length), md.slice(0, 500)]);
  } else {
    failCount++;
    allContent += '=== PAGE ' + (i + 1) + ' (FAILED) ===\nURL: ' + url + '\n\n';
    pageResults.push([String(i + 1), url, 'failed', '0', '']);
  }
});

return { allContent: allContent, successCount: successCount, failCount: failCount, totalPages: urls.length, pageResults: pageResults };

const data = $.steps.compileScrapeResults.output;
const goal = $.input.extractionGoal || 'Extract all key information';

let prompt = 'You are a web data extraction specialist. Analyze scraped content from ' + data.successCount + ' pages.\n\n';
prompt += 'EXTRACTION GOAL: ' + goal + '\n\n';
prompt += data.allContent + '\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "summary": "2-3 sentence overall summary",\n';
prompt += '  "pages": [{ "index": 1, "url": "", "title": "", "keyData": [""], "status": "success" }],\n';
prompt += '  "extractedData": [{ "category": "", "items": [""] }],\n';
prompt += '  "insights": [""],\n';
prompt += '  "totalDataPoints": 0\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw.slice(0, 300), pages: [], extractedData: [], insights: [], totalDataPoints: 0 }; }

const ai = $.steps.parseAI.output;
const stats = $.steps.compileScrapeResults.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Web Scraping Report', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Pages Scraped:*\n' + stats.successCount + '/' + stats.totalPages },
  { type: 'mrkdwn', text: '*Data Points:*\n' + (ai.totalDataPoints || 'N/A') }
] });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + (ai.summary || '').slice(0, 1800) } });
if (ai.insights && ai.insights.length > 0) {
  let insightText = '*Insights:*\n';
  ai.insights.slice(0, 5).forEach(function(ins, i) { insightText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: insightText.slice(0, 1800) } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Data saved to Google Sheets | Powered by Firecrawl + Claude AI' }] });
const fallbackText = 'Scraping Report: ' + stats.successCount + '/' + stats.totalPages + ' pages - ' + (ai.summary || '').slice(0, 80);
return { blocks, fallbackText };
